  1	import React, { FC, useEffect, useState } from 'react';
  2	import { Controller, FormProvider, useForm } from 'react-hook-form';
  3	import { useNavigate } from 'react-router-dom-v5-compat';
  4	
  5	import { RouteModel } from '@kubevirt-ui/kubevirt-api/console';
  6	import { k8sCreate, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
  7	import {
  8	  Checkbox,
  9	  Form,
 10	  FormGroup,
 11	  FormHelperText,
 12	  HelperText,
 13	  HelperTextItem,
 14	  PageSection,
 15	  PageSectionVariants,
 16	  TextInput,
 17	} from '@patternfly/react-core';
 18	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 19	import { resourcePathFromModel } from '@utils/resources/shared';
 20	import { RouteKind } from '@utils/types';
 21	import { getValidNamespace } from '@utils/utils';
 22	
 23	import { HOST_FIELD_ID, NAME_FIELD_ID, PATH_FIELD_ID, SECURITY_FIELD_ID } from './constants';
 24	import RouteFormActions from './RouteFormActions';
 25	import ServiceSelector from './ServiceSelector';
 26	import TLSTermination from './TLSTermination';
 27	
 28	type RouteFormProps = {
 29	  formData: RouteKind;
 30	  onChange: (newFormData: RouteKind) => void;
 31	};
 32	
 33	const RouteForm: FC<RouteFormProps> = ({ formData, onChange: onFormChange }) => {
 34	  const { t } = useNetworkingTranslation();
 35	  const navigate = useNavigate();
 36	  const [apiError, setError] = useState<Error>(null);
 37	  const [activeNamespace] = useActiveNamespace();
 38	  const namespace = getValidNamespace(activeNamespace);
 39	
 40	  const methods = useForm<RouteKind>({
 41	    defaultValues: formData,
 42	  });
 43	
 44	  const { control, handleSubmit, register, watch } = methods;
 45	
 46	  const route = watch();
 47	
 48	  useEffect(() => {
 49	    onFormChange(route);
 50	  }, [onFormChange, route]);
 51	
 52	  const tls = watch('spec.tls');
 53	
 54	  const isSecured = Boolean(tls);
 55	
 56	  const onSubmit = (data: RouteKind) => {
 57	    k8sCreate({ data, model: RouteModel })
 58	      .then(() => {
 59	        navigate(resourcePathFromModel(RouteModel, data?.metadata?.name, namespace));
 60	      })
 61	      .catch((err) => {
 62	        setError(err);
 63	      });
 64	  };
 65	
 66	  return (
 67	    <PageSection variant={PageSectionVariants.light}>
 68	      <FormProvider {...methods}>
 69	        <Form onSubmit={handleSubmit(onSubmit)}>
 70	          <FormGroup fieldId={NAME_FIELD_ID} isRequired label={t('Name')}>
 71	            <TextInput id={NAME_FIELD_ID} {...register('metadata.name', { required: true })} />
 72	
 73	            <FormHelperText>
 74	              <HelperText>
 75	                <HelperTextItem>
 76	                  {t('A unique name for the Route within the project')}
 77	                </HelperTextItem>
 78	              </HelperText>
 79	            </FormHelperText>
 80	          </FormGroup>
 81	          <FormGroup fieldId={HOST_FIELD_ID} isRequired label={t('Hostname')}>
 82	            <TextInput id={HOST_FIELD_ID} {...register('spec.host', { required: true })} />
 83	            <FormHelperText>
 84	              <HelperText>
 85	                <HelperTextItem>
 86	                  {t('Public hostname for the Route. If not specified, a hostname is generated.')}
 87	                </HelperTextItem>
 88	              </HelperText>
 89	            </FormHelperText>
 90	          </FormGroup>
 91	          <FormGroup fieldId={PATH_FIELD_ID} isRequired label={t('Path')}>
 92	            <TextInput id={PATH_FIELD_ID} {...register('spec.path', { required: true })} />
 93	            <FormHelperText>
 94	              <HelperText>
 95	                <HelperTextItem>
 96	                  {t('Path that the router watches to route traffic to the service.')}
 97	                </HelperTextItem>
 98	              </HelperText>
 99	            </FormHelperText>
100	          </FormGroup>
101	          <ServiceSelector namespace={namespace} />
102	
103	          <FormGroup fieldId={SECURITY_FIELD_ID} label={t('Security')}>
104	            <Controller
105	              control={control}
106	              defaultValue={true as never}
107	              name={'spec.tls'}
108	              render={({ field: { onChange, value } }) => (
109	                <Checkbox
110	                  id={SECURITY_FIELD_ID}
111	                  isChecked={value !== null && value !== undefined}
112	                  label={t('Secure Route')}
113	                  onChange={(event, checked) => onChange(checked ? {} : null)}
114	                />
115	              )}
116	            />
117	
118	            <FormHelperText>
119	              <HelperText>
120	                <HelperTextItem>
121	                  {t(
122	                    'Routes can be secured using several TLS termination types for serving certificates.',
123	                  )}
124	                </HelperTextItem>
125	              </HelperText>
126	            </FormHelperText>
127	          </FormGroup>
128	
129	          {isSecured && <TLSTermination />}
130	
131	          <RouteFormActions apiError={apiError} />
132	        </Form>
133	      </FormProvider>
134	    </PageSection>
135	  );
136	};
137	
138	export default RouteForm;

